electron.ipcMain.handle("opencaselist:fetchFileToTemp", async (_e, urlOrPath) => {
  try {
    const downloadUrl = /^https?:\/\//i.test(urlOrPath) ? urlOrPath : `https://api.opencaselist.com/v1/download?path=${encodeURIComponent(urlOrPath)}`;
    const headers = { Accept: "*/*" };
    if (ocCookie) headers["Cookie"] = ocCookie;
    const res = await fetch(downloadUrl, { headers });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const buffer2 = Buffer.from(await res.arrayBuffer());
    const cd = res.headers.get("content-disposition") ?? "";
    const fnMatch = cd.match(/filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/);
    let filename = fnMatch ? fnMatch[1].replace(/['"]/g, "").trim() : "";
    if (!filename) {
      const urlPart = downloadUrl.split("?")[0].split("/").pop() ?? "speech-doc";
      filename = decodeURIComponent(urlPart);
    }
    if (!filename.match(/\.\w+$/)) filename += ".docx";
    const tmpDir = path.join(electron.app.getPath("temp"), "warroom");
    await fs.promises.mkdir(tmpDir, { recursive: true });
    const safe = filename.replace(/[^a-z0-9._-]/gi, "_");
    const tempPath = path.join(tmpDir, `oc_${Date.now()}_${safe}`);
    await fs.promises.writeFile(tempPath, buffer2);
    trustPath(tempPath);
    return { ok: true, tempPath, filename, downloadUrl };
  } catch (e) {
    return { ok: false, error: e.message };
  }
});
